(()=>{'use strict';
const oldFetch=window.fetch.bind(window);
try{sessionStorage.removeItem('perf-v4')}catch{}
const CD_KEYS=['dc1','dc2','dc3','cd13'];
const N=v=>{if(v==null)return 0;if(typeof v==='number')return Number.isFinite(v)?v:0;const s=String(v).replace(/,/g,'').replace(/%/g,'').replace(/[()]/g,'').trim();const n=Number(s);return Number.isFinite(n)?n:0};
const norm=s=>String(s??'').replace(/\s+/g,' ').trim();
const compact=s=>norm(s).replace(/\s+/g,'').toUpperCase();
function hasCdName(text,key){const t=compact(text);if(key==='cd13')return t.includes('CD1+CD3');const n=key.replace('dc','');if(t.includes('CD1+CD3'))return false;return new RegExp('(^|[^A-Z0-9])CD'+n+'([^0-9]|$)').test(t)||new RegExp('(^|[^A-Z0-9])DC'+n+'([^0-9]|$)').test(t)}
function findVal(o,key,kind){const keys=Object.keys(o||{});const thai=kind==='target'?'เป้าหมาย':kind==='actual'?'การกระจาย':'INDEX';const eng=kind==='target'?'TARGET':kind==='actual'?'ACTUAL':'INDEX';for(const k of keys){const n=compact(k);if(!hasCdName(k,key))continue;if(n.includes(compact(thai))||n.includes(eng))return N(o[k])}return 0}
function cdMetric(row,key){const direct=row?.[key]||{};let target=N(direct.target),actual=N(direct.actual),index=N(direct.index);const src=row?.sellerReport||row?.cd||{};if(!target)target=findVal(src,key,'target');if(!actual)actual=findVal(src,key,'actual');if(!index)index=findVal(src,key,'index');if(target&&actual)index=actual/target*100;else if(index&&index<=1.5)index*=100;return{target,actual,index}}
function addLabels(pack){const labels=pack.labels=pack.labels||{},first=(pack.ps||[]).find(r=>r?.sellerReport)||{};const sr=first.sellerReport||{};for(const k of CD_KEYS){const hit=Object.keys(sr).find(x=>hasCdName(x,k)&&compact(x).includes('INDEX'));if(hit)labels[k]=k==='cd13'?'CD1+CD3':norm(hit).replace(/^Index\s*/i,'')}}
function sum(rows,key){let target=0,actual=0;(rows||[]).forEach(r=>{const v=cdMetric(r,key);target+=N(v.target);actual+=N(v.actual)});return{target,actual,index:target?actual/target*100:0}}
function patchCdOnly(pack){if(!pack||!Array.isArray(pack.ps))return pack;addLabels(pack);pack.ps.forEach(r=>CD_KEYS.forEach(k=>{r[k]=cdMetric(r,k)}));const rowsByAds=new Map();pack.ps.forEach(r=>{const id=r.ads||r.adsCode;if(!id)return;if(!rowsByAds.has(id))rowsByAds.set(id,[]);rowsByAds.get(id).push(r)});(pack.ads||[]).forEach(a=>{const id=a.ads||a.adsCode||a.code;const rows=rowsByAds.get(id)||[];CD_KEYS.forEach(k=>{a[k]=sum(rows,k)})});pack.ds=pack.ds||{};CD_KEYS.forEach(k=>{pack.ds[k]=sum(pack.ps||[],k)});return pack}
function codeOf(x){return String(x?.ps||x?.psCode||x?.ads||x?.adsCode||x?.code||'').trim()}
function indexBy(rows){const m=new Map();(rows||[]).forEach(r=>{const c=codeOf(r);if(c)m.set(c,r)});return m}
function copyCd(dst,src){if(!dst||!src)return;CD_KEYS.forEach(k=>{if(src[k])dst[k]=src[k]})}
function mergeCd(base,full){if(!base||!full)return base;patchCdOnly(full);base.labels={...(base.labels||{}),...(full.labels||{})};const fPs=indexBy(full.ps),fAds=indexBy(full.ads);(base.ps||[]).forEach(r=>copyCd(r,fPs.get(codeOf(r))));(base.ads||[]).forEach(r=>copyCd(r,fAds.get(codeOf(r))));if(full.ds){base.ds=base.ds||{};copyCd(base.ds,full.ds)}base.__cdAdapter='performance-cd-adapter-v3-merge-only';return base}
function baseUrl(url,path){return String(url).replace(/performance\/current\.min\.json(?:\?.*)?$/,path)}
function collectPaths(x,out=[],depth=0){if(!x||depth>6)return out;if(typeof x==='string'){let s=x.trim().replace(/^\/+/, '');if(/^performance\/.+\.json$/i.test(s)&&!/current\.min|active\.json|history-index|compare\//i.test(s))out.push(s);return out}if(Array.isArray(x)){x.forEach(v=>collectPaths(v,out,depth+1));return out}if(typeof x==='object'){Object.values(x).forEach(v=>collectPaths(v,out,depth+1));return out}return out}
async function getJson(url,path,headers){const r=await oldFetch(baseUrl(url,path),{headers,cache:'no-store'});if(!r.ok)throw Error(path+' '+r.status);return await r.json()}
async function sourcePack(url,headers,current){let paths=[];try{const active=await getJson(url,'performance/active.json',headers);paths=collectPaths(active)}catch(e){}paths.push(...collectPaths(current));paths=[...new Set(paths)];for(const p of paths){try{const j=await getJson(url,p,headers);if(j&&Array.isArray(j.ps)&&j.ps.some(r=>r?.sellerReport||r?.cd))return j}catch(e){}}
return null}
window.fetch=async function(input,init){const res=await oldFetch(input,init);try{const url=String(typeof input==='string'?input:input?.url||'');if(!url.includes('/performance/current.min.json'))return res;const current=await res.clone().json();const headers=init?.headers||{};const full=await sourcePack(url,headers,current);const json=full?mergeCd(current,full):patchCdOnly(current);return new Response(JSON.stringify(json),{status:res.status,statusText:res.statusText,headers:{'Content-Type':'application/json','Cache-Control':'no-store'}})}catch(e){console.warn('[performance-cd-adapter-v3-merge-only]',e);return res}}
})();
